INSERT INTO portfolio (title, client_task, specs, category, sort_order) VALUES ('RAZPC OBSIDIAN', 'Максимальная производительность для 4K гейминга', 'RTX 4090 / i9-14900K / 64GB / Custom Loop', 'Premium', 1), ('RAZPC SHADOW', 'Компактная рабочая станция для архитектора', 'RTX 4070 / R7 7700X / 32GB / White Build', 'Workstation', 2), ('RAZPC EMBER', 'Игровой ПК с красивой подсветкой для студента', 'RTX 4060 / R5 7600 / 16GB / ARGB Build', 'Gaming', 3), ('RAZPC VOID', 'Полностью чёрная сборка для стримера', 'RTX 4070S / R9 7900X / 64GB / All Black', 'Streaming', 4); INSERT INTO reviews (author_name, author_city, text, product_name, is_featured, sort_order) VALUES ('Александр К.', 'Краснодар', 'Заказывал RAZPC STRIKER для работы и игр. Ребята подобрали комплектующие точно под задачи, собрали аккуратно. Кабель-менеджмент — произведение искусства. Гарантия, тесты, полный отчёт. Рекомендую.', 'RAZPC STRIKER', true, 1), ('Михаил Т.', 'Краснодар', 'Брал APEX PRO для 3D-рендеринга. Производительность превзошла ожидания. Сборка идеальная, охлаждение работает без звука. Это не просто компьютер — это инструмент.', 'RAZPC APEX PRO', true, 2), ('Дмитрий В.', 'Сочи', 'Приехал из Сочи специально — стоило каждого километра. Custom loop выглядит невероятно, температуры на нуле. Буду заказывать снова.', NULL, false, 3), ('Анна С.', 'Краснодар', 'Собирали ПК для монтажа видео. Всё чётко: консультация, подбор, сборка за 3 дня. Уже полгода работает без единой проблемы.', NULL, true, 4);